insert into sentences (id, course_id, hanzi, pinyin, english, difficulty, grammar_notes) values
  ('s-1', 'course-mandarin-1', '你好！', 'Nǐ hǎo!', 'Hello!', 1, null),
  ('s-2', 'course-mandarin-1', '我叫小明。', 'Wǒ jiào Xiǎomíng.', 'My name is Xiaoming.', 1, '叫 + name introduces yourself'),
  ('s-3', 'course-mandarin-1', '我是学生。', 'Wǒ shì xuéshēng.', 'I am a student.', 1, 'Subject + 是 + noun'),
  ('s-4', 'course-mandarin-1', '你是中国人吗？', 'Nǐ shì Zhōngguórén ma?', 'Are you Chinese?', 2, 'Add 吗 for yes/no questions'),
  ('s-5', 'course-mandarin-1', '她是老师。', 'Tā shì lǎoshī.', 'She is a teacher.', 1, null),
  ('s-6', 'course-mandarin-1', '我有一个哥哥。', 'Wǒ yǒu yī gè gēge.', 'I have an older brother.', 2, '有 means to have'),
  ('s-7', 'course-mandarin-1', '我的妈妈很好。', 'Wǒ de māma hěn hǎo.', 'My mom is very good.', 2, '的 marks possession'),
  ('s-8', 'course-mandarin-1', '现在几点？', 'Xiànzài jǐ diǎn?', 'What time is it now?', 2, null),
  ('s-9', 'course-mandarin-1', '我喜欢喝茶。', 'Wǒ xǐhuān hē chá.', 'I like to drink tea.', 2, null),
  ('s-10', 'course-mandarin-1', '请给我米饭。', 'Qǐng gěi wǒ mǐfàn.', 'Please give me rice.', 2, null),
  ('s-11', 'course-mandarin-1', '这个多少钱？', 'Zhège duōshao qián?', 'How much is this?', 2, null),
  ('s-12', 'course-mandarin-1', '我的家很大。', 'Wǒ de jiā hěn dà.', 'My home is very big.', 2, null),
  ('s-13', 'course-mandarin-1', '手机在哪里？', 'Shǒujī zài nǎlǐ?', 'Where is the phone?', 2, '在 + location'),
  ('s-14', 'course-mandarin-1', '今天天气很冷。', 'Jīntiān tiānqì hěn lěng.', 'The weather is very cold today.', 2, null);
