-- Expand course content: Starter + Foundation units (28 lessons, 531 exercises)
-- Generated from src/data/course-content.ts — run: npm run db:generate-seed
-- Apply AFTER setup.sql on an existing database.

-- ========== SCHEMA ADDITIONS ==========
alter table vocab_items add column if not exists image_url text;
alter table vocab_items add column if not exists emoji text;

-- ========== CLEAR OLD COURSE CONTENT ==========
-- Reset user pointers to avoid FK violations when lessons are replaced
update user_progress
  set current_lesson_id = null,
      current_unit_id = null
  where course_id = 'course-mandarin-1';

delete from exercise_attempts
  where exercise_id in (
    select id from exercises
    where lesson_id in (select id from lessons where unit_id in (select id from units where course_id = 'course-mandarin-1'))
  );

delete from lesson_attempts
  where lesson_id in (select id from lessons where unit_id in (select id from units where course_id = 'course-mandarin-1'));

delete from vocab_memory
  where vocab_item_id in (select id from vocab_items where course_id = 'course-mandarin-1');

delete from exercises
  where lesson_id in (select id from lessons where unit_id in (select id from units where course_id = 'course-mandarin-1'));

delete from lesson_vocab
  where lesson_id in (select id from lessons where unit_id in (select id from units where course_id = 'course-mandarin-1'));

delete from lesson_sentences
  where lesson_id in (select id from lessons where unit_id in (select id from units where course_id = 'course-mandarin-1'));

delete from lessons
  where unit_id in (select id from units where course_id = 'course-mandarin-1');

delete from units where course_id = 'course-mandarin-1';

delete from sentences where course_id = 'course-mandarin-1';

delete from vocab_items where course_id = 'course-mandarin-1';

-- ========== INSERT EXPANDED COURSE CONTENT ==========







-- ========== RESET USER PROGRESS POINTERS ==========
update user_progress
  set current_lesson_id = 'lesson-sa-1',
      current_unit_id = 'unit-sa'
  where course_id = 'course-mandarin-1'
    and current_lesson_id is null;
